<template>
  <v-container class="full-height pa-0">
    <v-row class="fill-height">
      <v-col cols="2">
        <v-file-input label="File input" @change="selectFile"></v-file-input>
      </v-col>

      <v-spacer />

      <v-col cols="2">
        <v-select
          v-model="selected"
          :items="generics"
          item-text="display"
          label="Select"
          persistent-hint
          return-object
          single-line
        ></v-select>
      </v-col>

      <v-col cols="2">
        <v-select
          v-model="selectedSpectra"
          :items="spectras"
          item-text="name"
          label="Select Spectra"
          persistent-hint
          return-object
          single-line
          @change="selectedSpectraHandler($event)"
        ></v-select>
      </v-col>

      <!-- <v-spacer/> -->

      <v-col cols="12" class="pa-0 ma-0">
        <plotly
          class="graph"
          v-bind="selected.data.data"
          :data="selected.data.data"
          :layout="selected.data.layout"
          @selected="selectedHandler"
          @click="clickHandler"
        />
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import heatmaps from "./2DHeatmapSubplots";
import scatters from "./2DScatterSubplots";
import surfacePlot from "./3DSurfacePlot.js";
import interactivePlot from "./InteractivePlot.js";
import SpectraData from "./SpectraData.js";
// import traces from "./data.js";

export default {
  name: "picker",
  data() {
    return {
      generics: [heatmaps, scatters, interactivePlot, surfacePlot],
      selected: heatmaps,
      spectras: [
        { id: 0, name: "Spectra 1" },
        { id: 1, name: "Spectra 2" },
        { id: 2, name: "Spectra 3" },
        { id: 3, name: "Spectra 4" },
        { id: 4, name: "Spectra 5" },
        { id: 5, name: "Spectra 6" },
        { id: 6, name: "Spectra 7" },
        { id: 7, name: "Spectra 8" },
      ],
      selectedSpectra: undefined,
      currentFile: undefined,
      dataArray: undefined,
    };
  },
  created: function () {
    // console.log(traces);
    this.selectedSpectra = this.spectras[0];
  },
  methods: {
    selectFile(file) {
      // console.log(traces);
      if (file) {
        if (file.size != 1082368) {
          alert(`Corrupted file (size="${file.size}")`);
        } else {
          this.currentFile = file;
          console.log(file);

          let reader = new FileReader();
          reader.readAsArrayBuffer(file);

          var self = this;
          reader.onload = function () {
            console.log(reader.result);
            self.dataArray = new SpectraData(reader.result);

            // heatmaps
            for (var i = 0; i < 8; i++) {
              heatmaps.data.data[i].z = self.dataArray.data2d[i];
            }
            // scatters
            scatters.data.data = self.dataArray.data1d.map((d) => {
              return {
                type: "scatter",
                y: d,
              };
            });
            // interactive
            // console.log(interactivePlot.data);
            const points = self.dataArray.get2DPoints(
              self.selectedSpectra.id,
              0
            );
            console.log("points:", points);

            // main chart
            interactivePlot.data.data[0]["marker"]["color"] = points.color;
            interactivePlot.data.data[0]["x"] = points.x;
            interactivePlot.data.data[0]["y"] = points.y;
            // data for EdE processing
            const e = [...Array(256).keys()];
            const data = self.dataArray.data2d[self.selectedSpectra.id];
            // E chart
            var /*i,*/ j, x, y;
            interactivePlot.data.data[1]["x"] = e;
            interactivePlot.data.data[1]["y"] = [];
            for (i = 0; i < 256; i++) {
              interactivePlot.data.data[1]["y"].push(
                Math.max.apply(null, data[i])
              );
            }
            //dE chart
            interactivePlot.data.data[2]["x"] = e;
            interactivePlot.data.data[2]["y"] = [];
            for (j = 0; j < 256; j++) {
              (x = j), (y = 0);
              for (i = 1; i < 256; ++i) {
                if (data[i][j] > data[y][x]) {
                  y = i;
                }
              }
              interactivePlot.data.data[2]["y"].push(data[y][x]);
            }
            // surface
            surfacePlot.data.data[0] = {
              z: self.dataArray.data2d[self.selectedSpectra.id],
              type: "surface",
              colorscale: "Greys",
              reversescale: true,
            };
          };

          reader.onerror = function () {
            console.error(reader.error);
          };
        }
      } else {
        //TODO clear data
      }
    },
    selectedSpectraHandler(event) {
      console.log("selectedSpectraHandler", event.id, event.name);
      console.log(this.selectedSpectra);
      // interactive
      const points = this.dataArray
        ? this.dataArray.get2DPoints(this.selectedSpectra.id, 0)
        : {
            color: [],
            x: [],
            y: [],
          };
      console.log("points:", points);
      // main chart
      interactivePlot.data.data[0]["marker"]["color"] = points.color;
      interactivePlot.data.data[0]["x"] = points.x;
      interactivePlot.data.data[0]["y"] = points.y;
      // data for EdE processing
      const e = [...Array(256).keys()];
      if (this.dataArray) {
        const data = this.dataArray.data2d[this.selectedSpectra.id];
        // E chart
        var i, j, x, y;
        interactivePlot.data.data[1]["x"] = e;
        interactivePlot.data.data[1]["y"] = [];
        for (i = 0; i < 256; i++) {
          interactivePlot.data.data[1]["y"].push(Math.max.apply(null, data[i]));
        }
        //dE chart
        interactivePlot.data.data[2]["x"] = e;
        interactivePlot.data.data[2]["y"] = [];
        for (j = 0; j < 256; j++) {
          (x = j), (y = 0);
          for (i = 1; i < 256; ++i) {
            if (data[i][j] > data[y][x]) {
              y = i;
            }
          }
          interactivePlot.data.data[2]["y"].push(data[y][x]);
        }
      } else {
        interactivePlot.data.data[1]["x"] = e;
        interactivePlot.data.data[1]["y"] = [];
        interactivePlot.data.data[2]["x"] = e;
        interactivePlot.data.data[2]["y"] = [];
      }
      // surface
      surfacePlot.data.data[0] = {
        z: this.dataArray ? this.dataArray.data2d[this.selectedSpectra.id] : [],
        type: "surface",
        colorscale: "Greys",
        reversescale: true,
      };
    },
    selectedHandler(points, id) {
      console.log("selectedHandler", points, id);
    },
    clickHandler(data) {
      if (this.selected === heatmaps) {
        console.log("clickHandler", data.points[0].curveNumber);
        this.selected = interactivePlot;
        this.selectedSpectra = this.spectras[data.points[0].curveNumber];
        this.selectedSpectraHandler(this.selectedSpectra);
      } else {
        console.log("Skip click handling");
      }
    },
  },
};
</script>
<style>
.graph {
  height: 80vh;
}
</style>
